    </div>
    <div class="desktop-icon" data-app="notepad">
      <div class="icon">📝</div>
      <div class="label">Notepad</div>
    </div>
    <div class="desktop-icon" data-app="files" data-path="/home/user/Documents">
      <div class="icon">📂</div>
      <div class="label">Documents</div>
    </div>
    <div class="desktop-icon" data-app="files" data-path="/home/user">
      <div class="icon">🏠</div>
