<script>
/* =========================================================
   FILESYSTEM DATA
   ========================================================= */
const fs = {
  '/': ['bin', 'etc', 'home', 'usr', 'var'],
  '/bin': ['bash', 'cat', 'chmod', 'cp', 'echo', 'grep', 'ls', 'mkdir', 'mv', 'pwd', 'rm', 'sh', 'touch'],
  '/etc': ['apt', 'fstab', 'hostname', 'hosts', 'passwd', 'resolv.conf', 'shadow', 'sudoers'],
  '/etc/apt': ['sources.list', 'trusted.gpg'],
  '/home': ['user'],
  '/home/user': ['Documents', 'Downloads', 'Music', 'Pictures', 'Videos', '.bashrc', '.profile', 'README.md'],
  '/home/user/Documents': ['notes.txt', 'resume.pdf', 'todo.md', 'project-plan.md', 'budget.csv'],
  '/home/user/Downloads': ['chrome.deb', 'firefox.deb', 'archive.zip', 'image.png', 'installer.exe'],
  '/home/user/Music': ['song1.mp3', 'song2.mp3', 'album.flac', 'playlist.m3u'],
  '/home/user/Pictures': ['wallpaper.jpg', 'vacation.png', 'screenshot.png', 'avatar.gif', 'family.jpg'],
  '/home/user/Videos': ['movie.mp4', 'clip.webm', 'tutorial.mkv'],
  '/usr': ['bin', 'lib', 'local', 'share', 'src'],
  '/usr/bin': ['firefox', 'gnome-terminal', 'node', 'python3', 'vim', 'code'],
  '/usr/lib': ['x86_64-linux-gnu'],
  '/usr/local': ['bin', 'share'],
  '/usr/share': ['icons', 'themes'],
  '/usr/src': ['linux-headers-5.15.0'],
  '/usr/lib/x86_64-linux-gnu': ['libc.so.6', 'libm.so.6'],
  '/usr/local/bin': [],
  '/usr/local/share': [],
  '/usr/share/icons': ['hicolor'],
  '/usr/share/themes': ['Yaru', 'Adwaita'],
  '/usr/src/linux-headers-5.15.0': ['Makefile', 'README'],
  '/var': ['log', 'tmp', 'www'],
  '/var/log': ['syslog', 'auth.log', 'kern.log', 'dpkg.log'],
  '/var/tmp': [],
  '/var/www': ['html'],
  '/var/www/html': ['index.html', 'style.css']
};

const FILE_EXTS = {
  '.txt': '📄', '.pdf': '📕', '.md': '📝', '.doc': '📘', '.docx': '📘', '.csv': '📊',
  '.png': '🖼️', '.jpg': '🖼️', '.gif': '🖼️', '.jpeg': '🖼️', '.svg': '🖼️', '.bmp': '🖼️',
  '.mp3': '🎵', '.wav': '🎵', '.flac': '🎵', '.m3u': '🎵', '.ogg': '🎵',
  '.mp4': '🎬', '.webm': '🎬', '.avi': '🎬', '.mkv': '🎬', '.mov': '🎬',
  '.zip': '📦', '.tar': '📦', '.gz': '📦', '.deb': '📦', '.exe': '📦', '.rar': '📦', '.7z': '📦',
  '.html': '🌐', '.css': '🎨', '.js': '⚙️', '.json': '⚙️', '.conf': '⚙️', '.xml': '⚙️',
  '.log': '📜', '.so': '⚙️', '.list': '📜', '.iso': '💿', '.img': '💿',
  '.sh': '⚙️', '.py': '🐍', '.c': '⚙️', '.cpp': '⚙️', '.h': '⚙️', '.rs': '⚙️',
  '.gpg': '🔒', '.key': '🔑', '.pem': '🔒', '.md5': '🔒',
  '.png': '🖼️'
};

function getIconForName(name) {
  if (name.startsWith('.')) {
    const ext = name.substring(name.lastIndexOf('.')).toLowerCase();
    return FILE_EXTS[ext] || '📄';
  }
  if (name.includes('.')) {
    const ext = name.substring(name.lastIndexOf('.')).toLowerCase();
    if (FILE_EXTS[ext]) return FILE_EXTS[ext];
  }
  return '📄';
}

/* =========================================================
   FILES APP
   ========================================================= */
let currentPath = '/';

function joinPath(base, name) {
  if (base === '/') return '/' + name;
  return base + '/' + name;
}

function parentPath(p) {
  if (p === '/') return '/';
  const parts = p.split('/').filter(x => x);
  parts.pop();
  return parts.length === 0 ? '/' : '/' + parts.join('/');
}

function navigateTo(path) {
  if (!fs.hasOwnProperty(path)) {
    showNotification('Path not found: ' + path);
    return false;
  }
  currentPath = path;
  renderFiles();
  return true;
}

function renderFiles() {
  const content = document.getElementById('files-content');
  const pathInput = document.getElementById('files-path');
  const upBtn = document.getElementById('files-up');
  const status = document.getElementById('files-status');

  pathInput.value = currentPath;
  upBtn.disabled = currentPath === '/';
  content.innerHTML = '';

  const items = fs[currentPath] || [];
  if (items.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'empty-folder';
    empty.textContent = 'This folder is empty';
    content.appendChild(empty);
    status.textContent = '0 items';
    return;
  }

  // Sort: folders first, then files, alphabetically (case-insensitive)
  const sorted = [...items].sort((a, b) => {
    const aFull = joinPath(currentPath, a);
    const bFull = joinPath(currentPath, b);
    const aDir = fs.hasOwnProperty(aFull);
    const bDir = fs.hasOwnProperty(bFull);
    if (aDir !== bDir) return aDir ? -1 : 1;
    return a.toLowerCase().localeCompare(b.toLowerCase());
  });

  sorted.forEach(name => {
    const fullPath = joinPath(currentPath, name);
    const isFolder = fs.hasOwnProperty(fullPath);
    const icon = isFolder ? '📁' : getIconForName(name);

    const item = document.createElement('div');
    item.className = 'fs-item';
    item.dataset.name = name;
    item.dataset.path = fullPath;

    const iconEl = document.createElement('div');
    iconEl.className = 'icon';
    iconEl.textContent = icon;
    const nameEl = document.createElement('div');
    nameEl.className = 'name';
    nameEl.textContent = name;
    item.appendChild(iconEl);
    item.appendChild(nameEl);

    if (isFolder) {
      item.addEventListener('dblclick', () => navigateTo(fullPath));
    } else {
      item.addEventListener('dblclick', () => {
        showNotification('Cannot open "' + name + '" — this is a demo filesystem.');
      });
    }

    item.addEventListener('click', (e) => {
      document.querySelectorAll('.fs-item.selected').forEach(s => s.classList.remove('selected'));
      item.classList.add('selected');
      e.stopPropagation();
    });

    content.appendChild(item);
  });

  const folders = sorted.filter(n => fs.hasOwnProperty(joinPath(currentPath, n))).length;
  const files = sorted.length - folders;
  status.textContent = folders + ' folder' + (folders !== 1 ? 's' : '') + ', ' +
                       files + ' file' + (files !== 1 ? 's' : '');
}

document.getElementById('files-up').addEventListener('click', () => {
  if (currentPath !== '/') navigateTo(parentPath(currentPath));
});

document.getElementById('files-home').addEventListener('click', () => {
  navigateTo('/home/user');
});

document.getElementById('files-refresh').addEventListener('click', renderFiles);

const filesPathInput = document.getElementById('files-path');
filesPathInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    let val = filesPathInput.value.trim();
    if (!val) { filesPathInput.value = currentPath; return; }
    if (!val.startsWith('/')) val = '/' + val;
    if (val.length > 1 && val.endsWith('/')) val = val.replace(/\/+$/, '') || '/';
    if (!navigateTo(val)) {
      filesPathInput.value = currentPath;
    }
  }
  if (e.key === 'Escape') {
    filesPathInput.value = currentPath;
    filesPathInput.blur();
  }
});

// Click in content area to deselect
document.getElementById('files-content').addEventListener('click', (e) => {
  if (e.target.id === 'files-content') {
    document.querySelectorAll('.fs-item.selected').forEach(s => s.classList.remove('selected'));
  }
});

/* =========================================================
   WINDOW MANAGEMENT
   ========================================================= */
let topZ = 100;

function bringToFront(win) {
  topZ++;
  win.style.zIndex = topZ;
}

function openWindow(id) {
  const win = document.getElementById(id);
  if (!win) return;
  if (!win.classList.contains('open')) {
    win.classList.add('open');
    if (!win.dataset.positioned) {
      const rect = win.getBoundingClientRect();
      const w = rect.width || 500;
      const h = rect.height || 320;
      win.style.left = Math.max(20, Math.floor((window.innerWidth - w) / 2)) + 'px';
      win.style.top = Math.max(40, Math.floor((window.innerHeight - h) / 2 - 40)) + 'px';
      win.dataset.positioned = '1';
    }
  }
  bringToFront(win);
  if (id === 'files-window') {
    document.getElementById('open-files').classList.add('active');
  } else if (id === 'notepad-window') {
    document.getElementById('open-notepad').classList.add('active');
  }
}

function closeWindow(id) {
  const win = document.getElementById(id);
  if (!win) return;
  win.classList.remove('open');
  if (id === 'files-window') document.getElementById('open-files').classList.remove('active');
  if (id === 'notepad-window') document.getElementById('open-notepad').classList.remove('active');
}

