let dragState = null;

document.querySelectorAll('.window').forEach(win => {
  const tb = win.querySelector('.titlebar');
  tb.addEventListener('mousedown', (e) => {
    if (e.target.closest('.win-close')) return;
    if (e.button !== 0) return;
    const rect = win.getBoundingClientRect();
    dragState = {
      win: win,
      startX: e.clientX,
      startY: e.clientY,
      startLeft: rect.left,
      startTop: rect.top
    };
    document.body.style.cursor = 'grabbing';
    e.preventDefault();
  });
});

document.addEventListener('mousemove', (e) => {
  if (!dragState) return;
  const dx = e.clientX - dragState.startX;
  const dy = e.clientY - dragState.startY;
  let newLeft = dragState.startLeft + dx;
  let newTop = dragState.startTop + dy;
  newLeft = Math.max(-dragState.win.offsetWidth + 80, Math.min(window.innerWidth - 80, newLeft));
  newTop = Math.max(0, Math.min(window.innerHeight - 70, newTop));
  dragState.win.style.left = newLeft + 'px';
  dragState.win.style.top = newTop + 'px';
});

document.addEventListener('mouseup', () => {
  if (dragState) {
    dragState = null;
    document.body.style.cursor = '';
  }
});

