let notifEl = null;
let notifTimeout = null;
function showNotification(msg) {
  if (!notifEl) {
    notifEl = document.createElement('div');
    notifEl.id = 'notification';
    notifEl.style.opacity = '0';
    notifEl.style.transform = 'translateX(-50%) translateY(20px)';
    document.body.appendChild(notifEl);
  }
  notifEl.textContent = msg;
  // Force reflow
  void notifEl.offsetWidth;
  notifEl.style.opacity = '1';
  notifEl.style.transform = 'translateX(-50%) translateY(0)';
  if (notifTimeout) clearTimeout(notifTimeout);
  notifTimeout = setTimeout(() => {
    notifEl.style.opacity = '0';
    notifEl.style.transform = 'translateX(-50%) translateY(20px)';
  }, 2500);
}

/* =========================================================
   NOTEPAD APP
   ========================================================= */
let tabs = [];
let activeTabId = null;
const STORAGE_KEY = 'ubuntu-web-notepad-v1';

function loadState() {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const data = JSON.parse(saved);
      if (data && Array.isArray(data.tabs) && data.tabs.length > 0) {
        tabs = data.tabs.map(t => ({
          id: t.id || generateId(),
          title: typeof t.title === 'string' ? t.title : 'Untitled',
          content: typeof t.content === 'string' ? t.content : ''
        }));
        activeTabId = data.activeTabId;
        if (!tabs.find(t => t.id === activeTabId)) {
          activeTabId = tabs[0].id;
        }
        return;
      }
    }
  } catch (e) {
    console.warn('Failed to load notepad state', e);
  }
  createNewTab(true);
}

function saveState() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({
      tabs: tabs,
      activeTabId: activeTabId
    }));
  } catch (e) {
    console.warn('Failed to save notepad state', e);
  }
}

function generateId() {
  return 't_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);
}

function deriveTitle(content) {
  const firstLine = (content || '').split('\n')[0].trim();
  if (!firstLine) return 'Untitled';
  return firstLine.length > 22 ? firstLine.slice(0, 22) + '…' : firstLine;
}

function createNewTab(silent) {
  const tab = {
    id: generateId(),
    title: 'Untitled',
    content: ''
  };
  tabs.push(tab);
  activeTabId = tab.id;
  renderTabs();
  if (!silent) {
    saveState();
    setTimeout(() => document.getElementById('editor').focus(), 0);
  }
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = '';
  tabs.forEach(tab => {
    const el = document.createElement('div');
    el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
    el.dataset.id = tab.id;

    const titleEl = document.createElement('span');
    titleEl.className = 'tab-title';
    titleEl.textContent = tab.title;
    titleEl.title = tab.title;

    const closeEl = document.createElement('button');
    closeEl.className = 'tab-close';
    closeEl.textContent = '×';
    closeEl.title = 'Close tab';
    closeEl.setAttribute('aria-label', 'Close tab');

    el.appendChild(titleEl);
    el.appendChild(closeEl);

    el.addEventListener('mousedown', (e) => {
      // Prevent dragging window when clicking tab
      e.stopPropagation();
    });

    el.addEventListener('click', (e) => {
      if (e.target === closeEl) return;
      switchToTab(tab.id);
    });

    closeEl.addEventListener('mousedown', (e) => {
      e.stopPropagation();
    });
    closeEl.addEventListener('click', (e) => {
      e.stopPropagation();
      closeTab(tab.id);
    });

    tabsEl.appendChild(el);
  });
  updateEditor();
}

function switchToTab(id) {
  if (activeTabId === id) return;
  activeTabId = id;
  renderTabs();
  saveState();
  document.getElementById('editor').focus();
}

function updateEditor() {
  const editor = document.getElementById('editor');
  const tab = tabs.find(t => t.id === activeTabId);
  if (tab) {
    if (editor.value !== tab.content) {
      const selStart = editor.selectionStart;
      const selEnd = editor.selectionEnd;
      editor.value = tab.content;
      try {
        editor.selectionStart = Math.min(selStart, tab.content.length);
        editor.selectionEnd = Math.min(selEnd, tab.content.length);
      } catch (e) {}
    }
  } else {
    editor.value = '';
  }
}

function closeTab(id) {
  if (tabs.length === 1) {
    tabs[0].content = '';
    tabs[0].title = 'Untitled';
    activeTabId = tabs[0].id;
  } else {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    const wasActive = activeTabId === id;
    tabs.splice(idx, 1);
    if (wasActive) {
      activeTabId = tabs[Math.max(0, idx - 1)].id;
    }
  }
  renderTabs();
  saveState();
}

document.getElementById('new-tab').addEventListener('mousedown', (e) => {
  e.stopPropagation();
});
document.getElementById('new-tab').addEventListener('click', (e) => {
  e.stopPropagation();
  createNewTab();
});

const editor = document.getElementById('editor');
editor.addEventListener('input', (e) => {
  const tab = tabs.find(t => t.id === activeTabId);
  if (!tab) return;
  tab.content = e.target.value;
  const newTitle = deriveTitle(tab.content);
  if (tab.title !== newTitle) {
    tab.title = newTitle;
    const tabEl = document.querySelector('.tab[data-id="' + tab.id + '"] .tab-title');
    if (tabEl) {
      tabEl.textContent = newTitle;
      tabEl.title = newTitle;
    }
  }
  saveState();
});

editor.addEventListener('blur', () => saveState());

editor.addEventListener('keydown', (e) => {
  if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 's') {
    e.preventDefault();
    saveState();
    showNotification('Saved ✓');
  }
  if (e.key === 'Tab' && !e.shiftKey) {
    e.preventDefault();
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
    editor.selectionStart = editor.selectionEnd = start + 2;
    editor.dispatchEvent(new Event('input'));
  }
});

